mapper.insert:
INSERT INTO ${schema}.popup (
	popup_ttl
	, popup_type
	, popup_cn
	, popup_img_file_path
	, popup_url_addr
	, popup_bgng_dt
	, popup_end_dt
	, pstn_x
	, pstn_y
	, size_w
	, size_h
	, open_yn
	, use_yn
	, reg_id
	, reg_dt
	, mdfcn_id
	, mdfcn_dt
) VALUES (
	#{popupTtl}
	, #{popupType}
	, #{popupCn}
	, #{popupImgFilePath}
	, #{popupUrlAddr}
	, #{popupBgngDt}
	, #{popupEndDt}
	, #{pstnX}
	, #{pstnY}
	, #{sizeW}
	, #{sizeH}
	, #{openYn}
	, 'Y'
	, #{regId}
	, NOW()
	, #{mdfcnId}
	, NOW()
)
